+            let span = info_span!("subscriber_scope");
+            let _guard = span.enter();
+
+            info!(
+                message = "structured",
+                flag = true,
+                count_i = -5_i64,
+                count_u = 42_u64,
+                ratio = 3.5_f64,
+                debug_val = ?vec![1, 2, 3]
+            );
+
+            debug!(message = "second_message");
